function u(e){if(e==null||e==="")return"0.00";const t=Number(e);return Number.isNaN(t)?"0.00":t.toFixed(2)}function i(e){return"¥"+u(e)}function a(e){if(!e)return"";const t=new Date(typeof e=="number"?e:String(e).replace(/-/g,"/"));if(Number.isNaN(t.getTime()))return String(e);const n=r=>String(r).padStart(2,"0");return`${t.getFullYear()}-${n(t.getMonth()+1)}-${n(t.getDate())} ${n(t.getHours())}:${n(t.getMinutes())}`}export{a as f,u as t,i as y};
